import grpc
from concurrent import futures
import time
import logging

from envoy.service.auth.v3 import external_auth_pb2
from envoy.service.auth.v3 import external_auth_pb2_grpc
from envoy.type.v3 import http_status_pb2
from google.rpc import status_pb2
from google.rpc import code_pb2

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)


class AuthorizationService(external_auth_pb2_grpc.AuthorizationServicer):
    def __init__(self, authorized_tokens=None, required_headers=None):
        self.authorized_tokens = authorized_tokens or {"valid-token-123", "admin-token-456"}
        self.required_headers = required_headers or []
        
    def Check(self, request, context):
        logger.info("Received authorization check request")
        
        # Extract headers from the request
        headers = {}
        if request.attributes.request.http.headers:
            headers = dict(request.attributes.request.http.headers)
        
        logger.info(f"Request headers: {headers}")
        logger.info(f"Request path: {request.attributes.request.http.path}")
        logger.info(f"Request method: {request.attributes.request.http.method}")
        
        # Check for required headers
        for required_header in self.required_headers:
            if required_header not in headers:
                logger.warning(f"Missing required header: {required_header}")
                return self._create_denied_response(
                    f"Missing required header: {required_header}",
                    401
                )
        
        # Check for authorization header
        auth_header = headers.get("authorization", "")
        
        if not auth_header:
            logger.warning("No authorization header found")
            return self._create_denied_response("Unauthorized: No authorization header", 401)
        
        # Extract token from Bearer token format
        token = self._extract_token(auth_header)
        
        if not token:
            logger.warning("Invalid authorization header format")
            return self._create_denied_response("Unauthorized: Invalid authorization header format", 401)
        
        # Validate token
        if token not in self.authorized_tokens:
            logger.warning(f"Invalid token: {token}")
            return self._create_denied_response("Unauthorized: Invalid token", 403)
        
        # Authorization successful
        logger.info(f"Authorization successful for token: {token}")
        return self._create_allowed_response(headers, token)
    
    def _extract_token(self, auth_header):
        """Extract token from Authorization header"""
        parts = auth_header.split()
        if len(parts) == 2 and parts[0].lower() == "bearer":
            return parts[1]
        return auth_header
    
    def _create_allowed_response(self, original_headers, token):
        """Create an allowed response with optional header modifications"""
        response = external_auth_pb2.CheckResponse()
        response.status.code = code_pb2.OK
        
        # Add custom headers to be forwarded to the upstream service
        ok_response = external_auth_pb2.OkHttpResponse()
        
        # Add custom header indicating the authenticated user/token
        header = ok_response.headers.add()
        header.key = "x-auth-user"
        header.value = token
        
        # Add timestamp header
        header = ok_response.headers.add()
        header.key = "x-auth-timestamp"
        header.value = str(int(time.time()))
        
        response.ok_response.CopyFrom(ok_response)
        
        return response
    
    def _create_denied_response(self, message, status_code):
        """Create a denied response with error message"""
        response = external_auth_pb2.CheckResponse()
        
        # Set the status code
        response.status.code = code_pb2.PERMISSION_DENIED
        response.status.message = message
        
        # Create denied response with HTTP status
        denied_response = external_auth_pb2.DeniedHttpResponse()
        denied_response.status.code = http_status_pb2.StatusCode.Value(f"_{status_code}")
        
        # Add response headers
        header = denied_response.headers.add()
        header.key = "content-type"
        header.value = "application/json"
        
        # Set response body
        denied_response.body = f'{{"error": "{message}"}}'
        
        response.denied_response.CopyFrom(denied_response)
        
        return response


def serve(port=50051, max_workers=10):
    """Start the gRPC server"""
    server = grpc.server(futures.ThreadPoolExecutor(max_workers=max_workers))
    
    # Create authorization service with custom configuration
